UPDATE posts
title = #{title}, content = #{content}, summary = #{summary}, cover_image_url = #{coverImageUrl}, view_count = #{viewCount}, like_count = #{likeCount}, comment_count = #{commentCount}, status = #{status}, visibility = #{visibility}, is_top = #{isTop}, published_at = #{publishedAt}, faction = #{faction}, region = #{region}, server = #{server}, body_type = #{bodyType}, gameplay = #{gameplay}, target = #{target}, contact_detail = #{contactDetail}, image_urls = #{imageUrls}, tags = #{tags}, updated_at = NOW()
