mapper.select:
SELECT
    p.id, p.user_id, p.title, p.content, p.summary, p.cover_image_url,
    p.view_count, p.like_count, p.comment_count, p.status, p.visibility,
    p.is_top, p.published_at, p.created_at, p.updated_at,
    p.faction, p.region, p.server, p.body_type, p.gameplay,
    p.target, p.contact_detail, p.image_urls, p.tags,
    u.id as author_id,
    u.username as author_username,
    u.nickname as author_nickname,
    u.avatar_url as author_avatar_url,
    CASE WHEN EXISTS (
        SELECT 1 FROM post_likes pl
        WHERE pl.post_id = p.id AND pl.user_id = #{query.currentUserId}
    ) THEN TRUE ELSE FALSE END as liked,
    CASE WHEN EXISTS (
        SELECT 1 FROM user_follows uf
        WHERE uf.follower_id = #{query.currentUserId} AND uf.following_id = p.user_id
    ) THEN TRUE ELSE FALSE END as followed,
    CASE WHEN EXISTS (
        SELECT 1 FROM user_follows uf
        WHERE uf.follower_id = p.user_id AND uf.following_id = #{query.currentUserId}
    ) THEN TRUE ELSE FALSE END as follow_me
FROM posts p
INNER JOIN users u ON p.user_id = u.id


        AND p.status = #{query.status}


        AND p.visibility = #{query.visibility}


        AND p.user_id = #{query.userId}


        AND p.faction = #{query.faction}


        AND p.region = #{query.region}


        AND p.server = #{query.server}


        AND p.body_type = #{query.bodyType}


        AND p.gameplay = #{query.gameplay}


        AND p.tags LIKE CONCAT('%', #{query.tag}, '%')




        ORDER BY (p.like_count * 3 + p.comment_count * 2 + p.view_count * 0.1 + 1)
            * EXP(-TIMESTAMPDIFF(HOUR, p.published_at, NOW()) / 72.0) DESC


        ORDER BY p.view_count ${query.sortDirection}


        ORDER BY p.like_count ${query.sortDirection}


        ORDER BY p.published_at ${query.sortDirection}


        ORDER BY p.published_at DESC

SELECT COUNT(*)
FROM posts p


        AND p.status = #{query.status}


        AND p.visibility = #{query.visibility}


        AND p.user_id = #{query.userId}


        AND p.faction = #{query.faction}


        AND p.region = #{query.region}


        AND p.server = #{query.server}


        AND p.body_type = #{query.bodyType}


        AND p.gameplay = #{query.gameplay}


        AND p.tags LIKE CONCAT('%', #{query.tag}, '%')

SELECT * FROM posts
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY published_at DESC

SELECT COUNT(*) > 0
FROM post_likes
WHERE user_id = #{userId}
  AND post_id = #{postId}

